import { useState, useEffect } from 'react';

export default function TradingBotApp() {
  const [botActive, setBotActive] = useState(false);
  const [strategy, setStrategy] = useState('buy-low-sell-high');
  const [targetToken, setTargetToken] = useState('ETH');
  const [tradeLog, setTradeLog] = useState<string[]>([]);
  const [balance, setBalance] = useState('0.00');
  const [settings, setSettings] = useState({
    buyThreshold: '5',
    sellThreshold: '5',
    tradeAmount: '0.1',
  });

  // Simulate price monitoring
  useEffect(() => {
    if (!botActive) return;

    const interval = setInterval(() => {
      const mockPrice = (Math.random() * 3000 + 1500).toFixed(2);
      const timestamp = new Date().toLocaleTimeString();

      // Simulate trade decision
      if (Math.random() > 0.7) {
        const action = Math.random() > 0.5 ? 'BUY' : 'SELL';
        const log = `[${timestamp}] ${action} ${settings.tradeAmount} ${targetToken} @ $${mockPrice}`;
        setTradeLog(prev => [log, ...prev].slice(0, 10));
      }
    }, 3000);

    return () => clearInterval(interval);
  }, [botActive, targetToken, settings]);

  return (
    <div className="h-full bg-gradient-to-br from-slate-900 via-purple-900 to-slate-900 text-white p-6 overflow-auto">
      {/* Header */}
      <div className="flex items-center justify-between mb-6">
        <div>
          <h1 className="text-2xl font-bold flex items-center gap-2">
            <span className="text-3xl">🤖</span>
            Trading Bot
          </h1>
          <p className="text-sm text-gray-400">Automated Trading System</p>
        </div>
        <div className="text-right">
          <p className="text-xs text-gray-400">Wallet Balance</p>
          <p className="text-xl font-mono text-green-400">${balance} USDT</p>
        </div>
      </div>

      {/* Bot Status */}
      <div className="bg-black/30 backdrop-blur rounded-lg p-4 mb-4 border border-purple-500/30">
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className={`w-3 h-3 rounded-full ${botActive ? 'bg-green-500 animate-pulse' : 'bg-gray-500'}`} />
            <span className="font-semibold">
              Bot Status: {botActive ? 'ACTIVE' : 'INACTIVE'}
            </span>
          </div>
          <button
            onClick={() => setBotActive(!botActive)}
            className={`px-6 py-2 rounded-lg font-semibold transition-all ${
              botActive 
                ? 'bg-red-600 hover:bg-red-700' 
                : 'bg-green-600 hover:bg-green-700'
            }`}
          >
            {botActive ? 'STOP BOT' : 'START BOT'}
          </button>
        </div>
      </div>

      {/* Strategy Settings */}
      <div className="grid grid-cols-2 gap-4 mb-4">
        <div className="bg-black/30 backdrop-blur rounded-lg p-4 border border-purple-500/30">
          <label className="block text-sm text-gray-400 mb-2">Strategy</label>
          <select 
            value={strategy}
            onChange={(e) => setStrategy(e.target.value)}
            className="w-full bg-black/50 border border-purple-500/30 rounded px-3 py-2 text-white"
          >
            <option value="buy-low-sell-high">Buy Low, Sell High</option>
            <option value="scalping">Scalping</option>
            <option value="trend-following">Trend Following</option>
            <option value="arbitrage">Arbitrage</option>
          </select>
        </div>

        <div className="bg-black/30 backdrop-blur rounded-lg p-4 border border-purple-500/30">
          <label className="block text-sm text-gray-400 mb-2">Target Token</label>
          <select 
            value={targetToken}
            onChange={(e) => setTargetToken(e.target.value)}
            className="w-full bg-black/50 border border-purple-500/30 rounded px-3 py-2 text-white"
          >
            <option value="ETH">ETH/USDT</option>
            <option value="BTC">BTC/USDT</option>
            <option value="SOL">SOL/USDT</option>
            <option value="BNB">BNB/USDT</option>
          </select>
        </div>
      </div>

      {/* Trade Settings */}
      <div className="bg-black/30 backdrop-blur rounded-lg p-4 mb-4 border border-purple-500/30">
        <h3 className="font-semibold mb-3">Trade Parameters</h3>
        <div className="grid grid-cols-3 gap-3">
          <div>
            <label className="block text-xs text-gray-400 mb-1">Buy Threshold (%)</label>
            <input
              type="number"
              value={settings.buyThreshold}
              onChange={(e) => setSettings({...settings, buyThreshold: e.target.value})}
              className="w-full bg-black/50 border border-purple-500/30 rounded px-2 py-1 text-white"
            />
          </div>
          <div>
            <label className="block text-xs text-gray-400 mb-1">Sell Threshold (%)</label>
            <input
              type="number"
              value={settings.sellThreshold}
              onChange={(e) => setSettings({...settings, sellThreshold: e.target.value})}
              className="w-full bg-black/50 border border-purple-500/30 rounded px-2 py-1 text-white"
            />
          </div>
          <div>
            <label className="block text-xs text-gray-400 mb-1">Trade Amount</label>
            <input
              type="number"
              value={settings.tradeAmount}
              onChange={(e) => setSettings({...settings, tradeAmount: e.target.value})}
              className="w-full bg-black/50 border border-purple-500/30 rounded px-2 py-1 text-white"
            />
          </div>
        </div>
      </div>

      {/* Trade Log */}
      <div className="bg-black/30 backdrop-blur rounded-lg p-4 border border-purple-500/30">
        <h3 className="font-semibold mb-3 flex items-center gap-2">
          📊 Trade Log
          {botActive && <span className="text-xs text-green-400">(Live)</span>}
        </h3>
        <div className="space-y-2 max-h-60 overflow-y-auto">
          {tradeLog.length === 0 ? (
            <p className="text-gray-500 text-sm text-center py-4">
              {botActive ? 'Monitoring markets...' : 'Start bot to see trades'}
            </p>
          ) : (
            tradeLog.map((log, i) => (
              <div 
                key={i}
                className="bg-black/40 rounded p-2 text-sm font-mono border-l-2 border-purple-500"
              >
                {log}
              </div>
            ))
          )}
        </div>
      </div>

      {/* Warning */}
      <div className="mt-4 bg-yellow-900/20 border border-yellow-500/30 rounded-lg p-3">
        <p className="text-xs text-yellow-300">
          ⚠️ <strong>Demo Mode:</strong> This is a simulation. Connect to real exchanges via API for live trading.
        </p>
      </div>
    </div>
  );
}
